15	
16	    val BEFORE = TaskInitializer<JavalinServletContext> { submitTask, servlet, ctx, requestUri ->
17	        servlet.router.findHttpHandlerEntries(HandlerType.BEFORE, requestUri).forEach { entry ->
18	            submitTask(LAST, Task(skipOnExceptionAndRedirect = true) { entry.handle(ctx, requestUri) })
19	        }
20	    }
21	
22	    val BEFORE_MATCHED = TaskInitializer<JavalinServletContext> { submitTask, servlet, ctx, requestUri ->
23	        val httpHandlerOrNull by javalinLazy {
24	            ctx.cachedHttpHandler { servlet.router.findFirstHttpHandlerEntry(ctx.method(), requestUri) }
25	        }
26	        val isResourceHandler = httpHandlerOrNull == null && (ctx.method() == HEAD || ctx.method() == GET)
27	        val matchedRouteRoles by javalinLazy { httpHandlerOrNull?.endpoint?.metadata(Roles::class.java)?.roles ?: emptySet() }
28	        val resourceRouteRoles by javalinLazy { servlet.cfg.resourceHandler?.resourceRouteRoles(ctx) ?: emptySet() }
29	        val willMatch by javalinLazy {
30	            ctx.setRouteRoles(if (isResourceHandler) resourceRouteRoles else matchedRouteRoles)
31	            ctx.cachedWillMatch { servlet.willMatch(ctx, requestUri) }
32	        }
33	
34	        servlet.router.findHttpHandlerEntries(HandlerType.BEFORE_MATCHED, requestUri).forEach { entry ->
35	            if (willMatch) {
36	                httpHandlerOrNull?.let { ctx.endpoints().matchedHttpEndpointInternal = it.endpoint }
37	                submitTask(LAST, Task(skipOnExceptionAndRedirect = true) {
38	                    entry.handle(ctx, requestUri)
39	                })
40	            }
41	        }
42	    }
43	
44	    val HTTP = TaskInitializer<JavalinServletContext> { submitTask, servlet, ctx, requestUri ->
45	        val entry = ctx.cachedHttpHandler { servlet.router.findFirstHttpHandlerEntry(ctx.method(), requestUri) }
46	        if (entry != null) {
47	            submitTask(
48	                LAST,
49	                Task {
50	                    val roles = entry.endpoint.metadata(Roles::class.java)?.roles ?: emptySet()
51	                    ctx.setRouteRoles(roles)
52	                    entry.handle(ctx, requestUri)
53	                }
54	            )
55	            return@TaskInitializer
56	        }
57	        submitTask(LAST, Task {
58	            if (ctx.method() == HEAD && servlet.router.hasHttpHandlerEntry(GET, requestUri)) { // return 200, there is a get handler
59	                return@Task
60	            }
61	            if (ctx.method() == HEAD || ctx.method() == GET) { // check for static resources (will write response if found)
62	                if (servlet.cfg.resourceHandler?.handle(ctx) == true) return@Task
63	                if (servlet.cfg.singlePageHandler.handle(ctx)) return@Task
64	            }
65	            // No match, status will be 404 or 405 after this point
66	            // The endpoint will still be the placeholder with path ""
67	            val availableHandlerTypes = MethodNotAllowedUtil.findAvailableHttpHandlerTypes(servlet.router, requestUri)
68	            if (servlet.cfg.http.prefer405over404 && availableHandlerTypes.isNotEmpty()) {
69	                throw MethodNotAllowedResponse(details = MethodNotAllowedUtil.availableHandlerTypes(ctx, availableHandlerTypes))
70	            }
71	            throw EndpointNotFound(method = ctx.method(), path = requestUri)
72	        })
73	    }
74	
75	    val AFTER_MATCHED = TaskInitializer<JavalinServletContext> { submitTask, servlet, ctx, requestUri ->
76	        val didMatch by javalinLazy { ctx.cachedWillMatch { servlet.willMatch(ctx, requestUri) } }
77	        servlet.router.findHttpHandlerEntries(HandlerType.AFTER_MATCHED, requestUri).forEach { entry ->
78	            if (didMatch) {
79	                submitTask(LAST, Task(skipOnExceptionAndRedirect = false) { entry.handle(ctx, requestUri) })
80	            }
81	        }
82	    }
83	
84	    val ERROR = TaskInitializer<JavalinServletContext> { submitTask, servlet, ctx, _ ->
85	        submitTask(LAST, Task(skipOnExceptionAndRedirect = false) { servlet.router.handleHttpError(ctx.statusCode(), ctx) })
86	    }
87	
88	    val AFTER = TaskInitializer<JavalinServletContext> { submitTask, servlet, ctx, requestUri ->
89	        servlet.router.findHttpHandlerEntries(HandlerType.AFTER, requestUri).forEach { entry ->
90	            submitTask(LAST, Task(skipOnExceptionAndRedirect = false) { entry.handle(ctx, requestUri) })
91	        }
92	    }
93	
94	    private fun JavalinServlet.willMatch(ctx: JavalinServletContext, requestUri: String) = when {
95	        ctx.method() == HEAD && this.router.hasHttpHandlerEntry(GET, requestUri) -> true
96	        ctx.cachedHttpHandler { this.router.findFirstHttpHandlerEntry(ctx.method(), requestUri) } != null -> true
97	        this.cfg.resourceHandler?.canHandle(ctx) == true -> true
98	        this.cfg.singlePageHandler.canHandle(ctx) -> true
99	        else -> false
100	    }
101	
102	}
